SELECT

FROM
    rdp_verify_code
WHERE
    verify_type = #{verifyType,javaType=com.clougence.clouddm.console.web.constants.VerifyType}
    AND
    verify_code_type=#{verifyCodeType,javaType=com.clougence.clouddm.console.web.constants.VerifyCodeType}
    AND
    uid = #{uid}

SELECT

FROM
    rdp_verify_code
WHERE
    verify_type = #{verifyType,javaType=com.clougence.clouddm.console.web.constants.VerifyType}
AND
    verify_code_type=#{verifyCodeType,javaType=com.clougence.clouddm.console.web.constants.VerifyCodeType}
AND
    phone=#{phone}
AND
    phone_area_code=#{areaCode,javaType=com.clougence.clouddm.console.web.dal.enumeration.AreaCode}
limit 1

mapper.update:
UPDATE rdp_verify_code SET
fail_times = #{failTimes},
last_fail_date = #{failDate}, gmt_modified = now() WHERE id = #{id}

UPDATE rdp_verify_code SET
verify_code = #{verifyCode},
verify_code_send_time = #{sendTime}, gmt_modified = now() WHERE id = #{id}

UPDATE
    rdp_verify_code
SET

    phone = #{phone}


    email = #{email}

WHERE
uid = #{uid}
AND
verify_type = #{verifyType,javaType=com.clougence.clouddm.console.web.constants.VerifyType}
AND
verify_code_type=#{verifyCodeType,javaType=com.clougence.clouddm.console.web.constants.VerifyCodeType}
